# DSM 7.2 Auth Update: username/password replaces API token
# Run: Set-ExecutionPolicy Bypass -Scope Process -Force; .\AUTHUPDATE.ps1

$RepoPath = "C:\Users\LionelMosley\Documents\HTML\Synology - DiskStation Monitor"
Set-Location $RepoPath
Write-Host "Applying DSM 7.2 auth update..." -ForegroundColor Cyan

# frontend\public\synology-monitor.html
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "frontend\public\synology-monitor.html"
$dir = Split-Path $fullPath -Parent
if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote frontend\public\synology-monitor.html" -ForegroundColor Green

# backend\src\workers\pollEngine.ts
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "backend\src\workers\pollEngine.ts"
$dir = Split-Path $fullPath -Parent
if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote backend\src\workers\pollEngine.ts" -ForegroundColor Green

# backend\src\routes\devices.ts
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "backend\src\routes\devices.ts"
$dir = Split-Path $fullPath -Parent
if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote backend\src\routes\devices.ts" -ForegroundColor Green

git add -A
git commit -m "feat: DSM 7.2 auth - username/password replaces API token, AES-256-GCM encrypted"
git push origin main

if ($LASTEXITCODE -eq 0) {
    Write-Host "`n Done! Railway + Netlify rebuilding with DSM 7.2 auth." -ForegroundColor Green
    Write-Host "   Register devices with: dsm-monitor / your-password" -ForegroundColor Cyan
} else {
    Write-Host "`n Push failed." -ForegroundColor Red
}
